INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'childhood-cancer-insurance', '어린이 암보험 — 태아·자녀 가입 시 챙길 점', '태아·어린이 암보험 가입 시 보장 범위, 소아암 특성, 납입면제 등 부모가 확인할 핵심을 정리했습니다.', '<p>어린이 암보험은 소아암과 어린이 특유의 위험을 대비합니다. 성인 상품과 보장 구조가 다른 부분이 있어 가입 전 확인이 필요합니다.</p>
<h2>확인할 점</h2>
<ul>
<li>소아암·백혈병 등 보장 범위와 진단비 수준</li>
<li>태아 가입 시 보장 개시 시점과 선천 이상 관련 보장</li>
<li>납입면제: 부모(계약자)나 자녀에게 특정 사유 발생 시 보험료 면제</li>
</ul>
<h2>어린이보험의 특징</h2>
<table>
<thead><tr><th>요소</th><th>특징</th></tr></thead>
<tbody>
<tr><td>가입 연령</td><td>태아·0세부터 가능</td></tr>
<tr><td>보장 기간</td><td>장기(성인까지 이어지는 설계)</td></tr>
<tr><td>보험료</td><td>어릴수록 유리한 경우</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>진단비만이 아니라 입원·통원·항암치료 보장도 함께 살펴야 실제 치료에 도움이 됩니다. 보장 기간이 길기 때문에 갱신 구조와 향후 보험료도 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>소아암 보장 범위·진단비 확인</li><li>납입면제 조건 점검</li><li>진단비+치료 보장 함께 설계</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","어린이보험","태아보험"]', '[{"q":"태아 때도 암보험에 가입하나요?","a":"태아 가입이 가능한 어린이보험이 있습니다. 보장 개시 시점과 선천 관련 보장을 확인하세요."},{"q":"납입면제가 무엇인가요?","a":"계약자나 피보험자에게 약관에서 정한 사유가 생기면 이후 보험료가 면제되는 기능입니다."},{"q":"진단비만 크게 들면 되나요?","a":"치료가 길 수 있어 입원·통원·항암 보장도 함께 보는 것이 실제 도움이 됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'cancer-recurrence-metastasis', '재발·전이암 보장 — 두 번째 암은 또 받을 수 있을까', '암의 재발·전이 시 진단비 추가 지급 여부와 약관상 재진단암·2차암 보장 구조를 정리했습니다.', '<p>암은 치료 후에도 재발·전이가 생길 수 있습니다. 이때 진단비를 다시 받을 수 있는지는 약관의 구조에 달려 있습니다.</p>
<h2>최초 1회 vs 재진단 보장</h2>
<ul>
<li>많은 진단비는 ''최초 1회'' 지급이 기본</li>
<li>재진단암(2차암) 보장 특약이 있으면 일정 조건에서 재지급</li>
</ul>
<h2>재진단암 보장의 조건</h2>
<p>재발·전이를 새로운 진단으로 인정받으려면 보통 일정 기간(예: 직전 진단 후 일정 시간) 경과와 의학적 확정 진단이 필요합니다. 같은 암의 연속 치료는 새 진단으로 보지 않을 수 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>지급</th></tr></thead>
<tbody>
<tr><td>최초 진단</td><td>진단비 지급</td></tr>
<tr><td>재진단(조건 충족)</td><td>특약 있으면 재지급</td></tr>
</tbody>
</table>
<h2>가입 시 확인</h2>
<p>장기적으로 재발 위험을 대비하려면 재진단암 보장이 포함됐는지, 지급 간격과 횟수 제한은 어떤지 확인하는 것이 좋습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>진단비는 보통 최초 1회</li><li>재진단암 특약이 있어야 재지급</li><li>경과기간·횟수 제한 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","재발암","전이"]', '[{"q":"암이 재발하면 진단비를 또 받나요?","a":"재진단암(2차암) 보장 특약이 있고 조건을 충족하면 재지급될 수 있습니다. 기본 진단비는 보통 최초 1회입니다."},{"q":"전이도 새 진단으로 보나요?","a":"약관 기준에 따라 다릅니다. 일정 경과기간과 확정 진단 요건을 충족해야 인정되는 경우가 많습니다."},{"q":"연속 치료 중에도 받나요?","a":"같은 암의 연속 치료는 새 진단으로 보지 않을 수 있습니다. 약관의 재진단 정의를 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('whole-life', 'legacy-estate-planning', '종신보험과 상속설계 — 유동성과 자산 이전', '종신보험이 상속에서 유동성 확보와 자산 이전 수단으로 활용되는 원리와 유의점을 정리했습니다.', '<p>종신보험은 사망 시 약정 보험금을 남기므로, 상속 과정에서 유동성을 확보하는 수단으로 활용되기도 합니다.</p>
<h2>상속에서의 역할</h2>
<ul>
<li>부동산 등 비유동 자산이 많을 때 현금 유동성 보완</li>
<li>남겨질 가족의 생활 자금 마련</li>
</ul>
<h2>수익자 지정의 중요성</h2>
<p>보험금은 지정 수익자에게 지급됩니다. 수익자를 명확히 지정하면 자금이 의도한 사람에게 전달되도록 설계할 수 있습니다. 다만 상속·세금 관계는 사안마다 복잡하므로 전문가 검토가 필요합니다.</p>
<table>
<thead><tr><th>상황</th><th>활용</th></tr></thead>
<tbody>
<tr><td>비유동 자산 많음</td><td>유동성 보완</td></tr>
<tr><td>유족 생활 보장</td><td>생활자금 마련</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>상속·증여·세금은 개인 상황에 따라 결과가 크게 달라지므로, 일반론에 의존하기보다 세무·법률 전문가와 함께 설계하는 것이 안전합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>비유동 자산의 유동성 보완 수단</li><li>수익자 지정으로 전달 설계</li><li>세금·상속은 전문가 검토 필수</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["종신보험","상속설계","유동성"]', '[{"q":"종신보험으로 상속세를 줄이나요?","a":"상속 관련 효과는 개인 상황과 세법에 따라 크게 다릅니다. 일반화하기 어려우니 세무 전문가와 상담하세요."},{"q":"수익자는 누구로 하나요?","a":"의도한 수령자를 명확히 지정하는 것이 중요합니다. 지정 방식에 따라 전달과 과세가 달라질 수 있습니다."},{"q":"유동성 확보가 왜 중요한가요?","a":"부동산 위주 자산은 즉시 현금화가 어려워, 종신보험금이 생활·정산 자금으로 도움이 될 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-child-insurance', '어린이 실손보험 — 자녀 의료비 대비 포인트', '자녀의 잦은 병원 이용을 대비하는 어린이 실손의 가입 시점·보장 범위와 성인 전환 시 유의점을 정리했습니다.', '<p>아이들은 감기·중이염·골절 등으로 병원 이용이 잦아, 실손보험의 효용이 큽니다. 어린이 실손은 가입 시점과 보장 범위를 잘 보고 들어야 합니다.</p>
<h2>가입 포인트</h2>
<ul>
<li>이른 시기 가입이 인수·보험료 면에서 유리한 경우</li>
<li>통원·입원·수술 보장 범위와 한도</li>
<li>비급여(주사·도수 등) 특약 조건</li>
</ul>
<h2>성장과 전환</h2>
<p>어린이 실손도 세대 규정을 따르며, 일정 시점에 갱신·재가입이 이뤄집니다. 성인이 되며 보장·보험료가 조정될 수 있으니 장기 구조를 확인하세요.</p>
<table>
<thead><tr><th>시기</th><th>확인</th></tr></thead>
<tbody>
<tr><td>가입 초기</td><td>보장 범위·한도</td></tr>
<tr><td>갱신·전환</td><td>보험료·세대 규정</td></tr>
</tbody>
</table>
<h2>유의점</h2>
<p>실손은 중복가입해도 비례보상이므로, 부모 보험과 중복되지 않게 정리하는 것이 보험료 면에서 효율적입니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>잦은 병원 이용에 실손 효용 큼</li><li>통원·입원·비급여 보장 확인</li><li>중복가입은 비례보상 — 정리 필요</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","어린이보험","의료비"]', '[{"q":"아이 실손은 언제 드는 게 좋나요?","a":"이른 시기 가입이 인수·보험료 면에서 유리한 경우가 많습니다. 보장 범위와 함께 비교하세요."},{"q":"부모 보험과 중복되면요?","a":"실손은 비례보상이라 중복은 보험료만 이중 부담일 수 있습니다. 중복을 정리하는 것이 효율적입니다."},{"q":"성인이 되면 어떻게 되나요?","a":"갱신·재가입을 거치며 보장과 보험료가 조정됩니다. 장기 구조를 미리 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-mental-health', '정신과 진료와 실손 — 어디까지 보장될까', '실손보험의 정신질환(F코드) 보장 확대 흐름과, 급여·비급여 구분에 따른 보장 차이를 정리했습니다.', '<p>과거에는 정신과 진료가 실손 보장에서 빠지는 경우가 많았지만, 일부 정신질환에 대해 보장이 확대되어 왔습니다. 다만 모든 항목이 보장되는 것은 아닙니다.</p>
<h2>보장 확대 흐름</h2>
<ul>
<li>일정 시점 이후 가입분부터 일부 정신질환(급여 항목) 보장이 넓어짐</li>
<li>증상·치료가 급여로 인정되는 범위가 핵심</li>
</ul>
<h2>급여·비급여 구분</h2>
<p>실손은 급여 본인부담과 비급여를 구분해 보장합니다. 정신과 진료도 급여로 처리되는 부분과 비급여(일부 상담·검사 등)에 따라 보장이 달라질 수 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>경향</th></tr></thead>
<tbody>
<tr><td>급여 진료</td><td>보장 가능성↑</td></tr>
<tr><td>비급여 상담 등</td><td>보장 제한 가능</td></tr>
</tbody>
</table>
<h2>확인 방법</h2>
<p>가입 시기와 약관에 따라 보장 범위가 다르므로, 본인 실손의 정신질환 보장 여부를 약관이나 보험사를 통해 확인하는 것이 정확합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>일부 정신질환 보장 확대 흐름</li><li>급여·비급여 구분이 핵심</li><li>가입 시기·약관별 차이 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","정신질환","F코드"]', '[{"q":"정신과 진료도 실손이 되나요?","a":"일부 정신질환의 급여 진료는 보장될 수 있습니다. 가입 시기·약관에 따라 범위가 다르니 확인이 필요합니다."},{"q":"상담료도 보장되나요?","a":"비급여 상담·검사 등은 보장이 제한될 수 있습니다. 급여 처리 여부가 관건입니다."},{"q":"내 실손은 보장될까요?","a":"가입 시기와 약관에 따라 다릅니다. 보험사나 약관에서 정신질환 보장 여부를 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'long-term-care-benefit', '장기요양·간병 보험금 — 노인장기요양등급과 보장', '노인장기요양보험 등급과 민간 간병보험의 관계, 장기요양 상태에서 받는 보험금 구조를 정리했습니다.', '<p>고령화로 간병 부담이 커지면서 장기요양·간병 보장의 중요성이 높아지고 있습니다. 공적 제도와 민간 보험을 함께 이해하면 도움이 됩니다.</p>
<h2>공적 노인장기요양보험</h2>
<ul>
<li>일상생활 수행 능력 등을 평가해 장기요양등급을 부여</li>
<li>등급에 따라 요양 서비스·재가급여 등을 지원</li>
</ul>
<h2>민간 간병·장기요양보험</h2>
<p>민간 보험은 장기요양등급 판정이나 약관이 정한 상태(예: 일정 등급 이상)에 해당하면 보험금을 지급하는 구조가 많습니다. 진단·등급 판정 자료가 청구의 근거가 됩니다.</p>
<table>
<thead><tr><th>구분</th><th>역할</th></tr></thead>
<tbody>
<tr><td>공적 제도</td><td>요양 서비스 지원</td></tr>
<tr><td>민간 보험</td><td>현금 보험금 보완</td></tr>
</tbody>
</table>
<h2>청구 시</h2>
<p>장기요양등급 판정 결과, 진단서 등 약관이 요구하는 자료를 준비하세요. 약관마다 지급 기준(등급·상태)이 다르므로 확인이 필요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>공적 제도는 서비스, 민간은 현금 보완</li><li>장기요양등급 판정이 청구 근거</li><li>약관별 지급 기준 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","장기요양","간병보험"]', '[{"q":"장기요양등급은 어떻게 받나요?","a":"국민건강보험공단에 신청해 일상생활 수행 능력 등을 평가받아 등급이 판정됩니다."},{"q":"민간 간병보험은 무엇을 보장하나요?","a":"약관이 정한 등급·상태에 해당하면 보험금을 지급해 공적 제도가 채우지 못하는 현금 부담을 보완합니다."},{"q":"어떤 서류가 필요한가요?","a":"장기요양등급 판정 결과와 진단서 등 약관이 요구하는 자료가 필요합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'dementia-diagnosis-benefit', '치매 진단비 — CDR 척도와 중증·경증 구분', '치매 진단비 지급 기준으로 쓰이는 CDR(임상치매척도)의 의미와 경증·중증 보장 차이를 정리했습니다.', '<p>치매 보장은 진단 기준이 명확해 분쟁이 상대적으로 적은 편이지만, 경증과 중증의 보장 차이를 알아야 합니다. 핵심 척도가 CDR입니다.</p>
<h2>CDR 척도란</h2>
<p>CDR(임상치매척도)은 인지·기능 손상 정도를 단계로 평가하는 척도입니다. 숫자가 클수록 중증을 의미하며, 약관은 보통 일정 CDR 단계 이상을 보장 기준으로 둡니다.</p>
<table>
<thead><tr><th>대략 구분</th><th>의미</th></tr></thead>
<tbody>
<tr><td>경도</td><td>경증치매</td></tr>
<tr><td>중등도</td><td>중간 단계</td></tr>
<tr><td>중증</td><td>중증치매(높은 CDR)</td></tr>
</tbody>
</table>
<h2>보장 구조</h2>
<ul>
<li>경증치매와 중증치매의 진단비가 다르게 설계되는 경우가 많음</li>
<li>중증일수록 진단비가 크고, 일부는 간병 보장과 연계</li>
</ul>
<h2>청구 시</h2>
<p>전문의의 진단과 CDR 평가, 인지기능 검사 결과 등 약관이 요구하는 자료가 필요합니다. 보장 기준 단계를 약관에서 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>CDR 단계로 보장 기준 판단</li><li>경증·중증 진단비 차등</li><li>전문의 진단·검사 자료 필요</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","치매","CDR"]', '[{"q":"CDR이 무엇인가요?","a":"인지·기능 손상 정도를 단계로 평가하는 임상치매척도입니다. 약관은 보통 일정 단계 이상을 보장 기준으로 둡니다."},{"q":"경증치매도 보장되나요?","a":"경증치매 진단비가 별도로 설계된 상품이 있습니다. 다만 중증보다 금액이 작은 경우가 많습니다."},{"q":"어떤 검사가 필요한가요?","a":"전문의 진단과 CDR 평가, 인지기능 검사 결과 등 약관이 요구하는 자료가 필요합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'roadside-and-rental-rider', '긴급출동·렌트 특약 — 사고·고장 시 도움이 되는 보장', '자동차보험의 긴급출동 서비스와 렌트(대차)·교통비 지원 특약의 차이와 활용법을 정리했습니다.', '<p>자동차보험에는 사고·고장 시 실질적 도움이 되는 부가 특약이 있습니다. 대표적으로 긴급출동 서비스와 렌트(대차) 지원입니다.</p>
<h2>긴급출동 서비스</h2>
<ul>
<li>배터리 충전, 타이어 교체, 견인, 비상 급유 등</li>
<li>연간 횟수·거리 제한이 있는 경우가 많음</li>
</ul>
<h2>렌트(대차) vs 교통비</h2>
<p>내 차가 사고로 수리에 들어가면, 가해자 측 보험에서 렌트(대차) 또는 교통비를 지원받을 수 있습니다. 내 차 수리 시 본인 특약으로 대차를 지원받는 상품도 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>내용</th></tr></thead>
<tbody>
<tr><td>긴급출동</td><td>고장·비상 상황 지원</td></tr>
<tr><td>대차/교통비</td><td>수리 기간 이동 보완</td></tr>
</tbody>
</table>
<h2>가입 시 확인</h2>
<p>긴급출동의 연간 한도와 대차 지원 일수·등급을 확인하세요. 자주 쓰는 서비스라면 한도가 넉넉한 특약이 유리합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>긴급출동은 고장·비상 지원</li><li>대차·교통비는 수리 기간 보완</li><li>연간 한도·일수 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","긴급출동","렌트특약"]', '[{"q":"긴급출동은 무제한인가요?","a":"대개 연간 횟수·거리 제한이 있습니다. 가입 특약의 한도를 확인하세요."},{"q":"사고로 차가 수리되면 렌트비를 받나요?","a":"가해자 측 보험에서 대차나 교통비를 지원받을 수 있고, 본인 특약으로 대차를 지원받는 상품도 있습니다."},{"q":"대차 등급은 무엇인가요?","a":"지원되는 렌트 차량의 등급·일수 기준입니다. 특약에 따라 다르므로 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'dashcam-accident-evidence', '교통사고 증거 확보 — 블랙박스와 현장 대응', '사고 직후 과실·보상에서 유리해지기 위한 블랙박스 활용과 현장 증거 확보, 신고 절차를 정리했습니다.', '<p>교통사고에서 과실비율과 보상은 결국 증거로 갈립니다. 사고 직후 침착하게 증거를 확보하면 부당한 불이익을 막을 수 있습니다.</p>
<h2>사고 직후 할 일</h2>
<ul>
<li>안전 확보 후 부상자 구호·신고</li>
<li>블랙박스 영상 보존(자동 삭제 전 백업)</li>
<li>현장 사진: 차량 위치, 파손 부위, 신호·차선, 상대 차량 번호</li>
</ul>
<h2>왜 증거가 중요한가</h2>
<p>과실비율은 기본과실에 사고 정황을 가감해 정해집니다. 객관적 영상·사진이 있으면 수정요소를 정확히 반영해 유리한 판단을 받을 수 있습니다.</p>
<table>
<thead><tr><th>증거</th><th>역할</th></tr></thead>
<tbody>
<tr><td>블랙박스</td><td>사고 경위 입증</td></tr>
<tr><td>현장 사진</td><td>위치·신호 등 정황</td></tr>
<tr><td>목격자</td><td>제3자 진술</td></tr>
</tbody>
</table>
<h2>이견이 클 때</h2>
<p>과실비율에 합의가 안 되면 과실비율분쟁심의위원회 심의를 활용할 수 있습니다. 증거가 충실할수록 결과가 명확해집니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>구호·신고가 최우선</li><li>블랙박스·현장 사진 즉시 확보</li><li>이견 크면 분쟁심의위원회</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","블랙박스","사고대응"]', '[{"q":"블랙박스 영상은 꼭 백업해야 하나요?","a":"저장 용량이 차면 자동 삭제될 수 있습니다. 사고 직후 해당 구간을 별도로 백업하세요."},{"q":"현장 사진은 무엇을 찍나요?","a":"차량 위치, 파손 부위, 신호·차선, 상대 차량 번호 등 정황을 폭넓게 남기세요."},{"q":"과실이 억울하면 어떻게 하나요?","a":"증거를 정리해 보험사에 이의를 제기하고, 합의가 안 되면 과실비율분쟁심의위원회를 활용할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('practice', 'compliance-incomplete-sale', '불완전판매 예방 — 설계사가 꼭 지켜야 할 3대 기본', '불완전판매를 막기 위한 설명의무·적합성 원칙·서류 확인 등 설계사 컴플라이언스의 핵심을 정리했습니다.', '<p>불완전판매는 민원과 계약 해지의 주요 원인이자, 설계사 신뢰를 무너뜨리는 위험입니다. 기본 원칙만 지켜도 대부분 예방할 수 있습니다.</p>
<h2>3대 기본</h2>
<ul>
<li>설명의무: 보장 내용·면책·해지환급금 등을 정확히 설명</li>
<li>적합성 원칙: 고객의 상황·필요에 맞는 상품 권유</li>
<li>서류 확인: 자필서명, 청약서 작성, 약관 전달</li>
</ul>
<h2>흔한 실수</h2>
<table>
<thead><tr><th>실수</th><th>위험</th></tr></thead>
<tbody>
<tr><td>단정적 수익 표현</td><td>분쟁·제재</td></tr>
<tr><td>면책 미설명</td><td>지급 거절 시 민원</td></tr>
<tr><td>자필서명 누락</td><td>품질보증해지 사유</td></tr>
</tbody>
</table>
<h2>핵심</h2>
<p>고객이 무엇을 가입했는지 스스로 설명할 수 있을 정도로 이해시키는 것이 최선의 예방입니다. 기록을 남기는 습관도 분쟁 시 보호막이 됩니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>설명의무·적합성·서류 확인</li><li>단정적 표현·면책 누락 금지</li><li>고객 이해와 기록이 최선의 방어</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["설계사실무","불완전판매","컴플라이언스"]', '[{"q":"불완전판매로 인정되면 어떻게 되나요?","a":"품질보증해지로 보험료가 환급되고, 설계사·회사에 제재가 따를 수 있습니다."},{"q":"가장 흔한 원인은요?","a":"면책·해지환급금 미설명, 단정적 수익 표현, 자필서명 누락 등이 대표적입니다."},{"q":"어떻게 예방하나요?","a":"설명의무·적합성 원칙을 지키고 서류를 정확히 갖추며, 고객이 스스로 이해하도록 설명하는 것이 핵심입니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('terms', 'grace-period-and-reinstatement', '보험료 연체와 부활 — 실효된 계약 되살리기', '보험료 연체 시 납입최고기간과 실효의 의미, 실효된 계약을 되살리는 부활 제도와 조건을 정리했습니다.', '<p>보험료를 못 내면 계약이 바로 사라지는 것은 아니지만, 방치하면 보장이 끊깁니다. 연체·실효·부활의 흐름을 알아두면 보장 공백을 막을 수 있습니다.</p>
<h2>연체와 실효</h2>
<ul>
<li>납입최고(독촉)기간: 연체 후 일정 기간 보험사가 납입을 안내</li>
<li>실효: 최고기간까지 내지 않으면 계약 효력이 정지</li>
</ul>
<h2>부활 제도</h2>
<p>실효된 계약도 일정 기간 내에는 부활을 신청할 수 있습니다. 보통 밀린 보험료와 이자를 내고, 다시 고지의무를 이행하면 보장이 되살아납니다.</p>
<table>
